import{_ as e,o as s,c as o,g as t}from"./chunks/framework.CpTXwe1b.js";const N=JSON.parse('{"title":"八五","description":"","frontmatter":{"title":"八五","date":"2021-03-06T22:43:52.000Z","length":"367字","time":"2分钟","aside":false,"hash":-1666904557},"headers":[],"relativePath":"idea/85.md","filePath":"idea/85.md"}'),n={name:"idea/85.md"},_=t("p",null,"一口气追了十三集觉醒年代，有好多感慨。",-1),a=t("p",null,"各种各样的细节和隐喻就不提了，这剧确实让我又对陈独秀这位熟悉的陌生人有了新的了解。",-1),l=t("p",null,"安徽人，确实挺秀的，就是照片上看起来木的很，不知道是不是导演组加戏。",-1),c=t("p",null,"两个在上海滩街头的孩子，让人瞬间想到另外一对上海滩流浪的兄弟。",-1),d=t("p",null,"看了下出品方是安徽省委和北京市委宣传部，所以自然夹带了些安徽的私货，譬如荷叶黄牛蹄。北京私货就不说了，都快成北大官方宣传片了。",-1),i=t("p",null,"钱玄同确实是个掀屋顶的主，蔡元培是个狡兔，胡适风华正茂，不过总提他白话诗白话文，也没具体介绍几个例子，多半是因为炸弹和蝴蝶确显幼稚，抛开时代背景以外拿不出手。",-1),p=t("p",null,"其实最意想不到的还是陈独秀父子关系的演绎，不知道有没有史实支撑。",-1),r=t("p",null,"总体上看似回顾历史，其实还是在讲当下的故事。百年前讲的是新文化，多半是破除；现在再谈文化自信，多半是传承。借古喻今我不反对，就是",-1),h=t("p",null,"润之和豫才的镜头给的太少啦！每帧都很宝贵。上三张图。蓑衣润寰、青衫润之、抄碑鲁迅。",-1),u=[_,a,l,c,d,i,p,r,h];function m(f,$,g,x,B,k){return s(),o("div",null,u)}const P=e(n,[["render",m]]);export{N as __pageData,P as default};
